<section class="card"><div class="actions"><h2>Quotations</h2><a class="button primary" href="/quotations/create">Create</a></div><table><tr><th>No</th><th>Customer</th><th>Date</th><th>Status</th><th>Total</th><th>Actions</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['quotation_number']) ?></td><td><?= e($r['company_name']) ?></td><td><?= e($r['quotation_date']) ?></td><td><?= e($r['status_name']) ?></td><td>₹<?= money($r['grand_total']) ?></td><td><a href="/quotations/<?= e($r['id']) ?>/edit">Edit</a> <a href="/quotations/<?= e($r['id']) ?>/pdf" target="_blank">PDF</a><form class="inline" method="post" action="/quotations/<?= e($r['id']) ?>/approve"><?= csrf_field() ?><button>Approve</button></form><form class="inline" method="post" action="/quotations/<?= e($r['id']) ?>/duplicate"><?= csrf_field() ?><button>Duplicate</button></form></td></tr><?php endforeach; ?></table></section>
